solution_code:
#include <cstring>
#include <iostream>

int main()
{
    const int maxLen{ 50 };
    char input[maxLen];
    std::cin.getline(input, maxLen);

    std::size_t len{ std::strlen(input) };

    char reversed[maxLen];
    for (std::size_t i{ 0 }; i < len; ++i)
        reversed[i] = input[len - 1 - i];
    reversed[len] = '\0';

    std::cout << len << '\n';
    std::cout << reversed << '\n';

    return 0;
}

